    http_tokens = "required"  # Critical: Require IMDSv2 tokens (blocks IMDSv1)
  }
}
```

```hcl
# Security group without CIFS open to the Internet
resource "aws_security_group" "<example_resource_name>" {
  name   = "<example_resource_name>"
  vpc_id = "<example_resource_id>"

  ingress {
    from_port   = 139
    to_port     = 139
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/8"] # CRITICAL: restrict CIFS (139); do not use 0.0.0.0/0
  }

  ingress {
    from_port   = 445
    to_port     = 445
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/8"] # CRITICAL: restrict CIFS (445); do not use 0.0.0.0/0
  }
}
```

```hcl
# Security group without CIFS open to the Internet
