```hcl
# Terraform: restrict SSH from the Internet
resource "aws_security_group" "<example_resource_name>" {
  vpc_id = "<example_resource_id>"

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/8"]  # Critical: do not use 0.0.0.0/0 or ::/0
  }
}
```

```hcl
# Restrict RDP (3389) from the Internet
resource "aws_security_group" "<example_resource_name>" {
  vpc_id = "<example_resource_id>"

  ingress {
    from_port   = 3389
    to_port     = 3389
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/8"] # FIX: not 0.0.0.0/0; restricts RDP to internal range
  }
}
```

```hcl
resource "aws_iam_account_password_policy" "<example_resource_name>" {
  minimum_password_length = 14  # Critical: enforces minimum password length >=14
}
```

```hcl
resource "aws_iam_account_password_policy" "<example_resource_name>" {
  password_reuse_prevention = 24  # Critical: require last 24 passwords cannot be reused
}
```

```hcl
resource "aws_iam_access_key" "<example_resource_name>" {
  user   = "<example_resource_name>"
  status = "Inactive" # Critical: disables the access key to ensure no active key is older than 90 days
}
```

